import React from 'react';
import './EyePanel.css';

export default function EyePanel() {
  return (
    <div className="eye-panel">
      <img className="eye-img" src="/eye-open.svg" alt="" draggable={false} />
      {/* white eyelids that slide away to reveal the eye */}
      <div className="lid lid-top" />
      <div className="lid lid-bottom" />
    </div>
  );
}
